/*
  # Update Australia Passport Complete Visa Requirements

  1. Updates for Australia Passport Holders
    - Fix all destination visa requirements with accurate, fact-checked data
    - Add bilateral visa waiver agreements for enhanced Schengen terms
    - Correct Brazil visa requirement (required since April 10, 2025)
    - Add New Zealand Trans-Tasman Travel Arrangement (indefinite residence)
    - Add Canada eTA requirement
    - Add China temporary visa-free arrangement details
    - Add Indonesia VoA requirement
    - Add Thailand 60-day visa-free stay (increased in 2024)
    - Add Turkey eVisa requirement
    - Add Vietnam eVisa requirement
    - Update all ETIAS information for Schengen countries
    - Set last_verified to 2026-02-19

  2. Key Corrections
    - Australia-Schengen Bilateral Agreements: Austria, Czech Republic, France, Germany, Greece, Italy, Netherlands, Poland, Portugal, Spain, Switzerland (90 days per entry regardless of other Schengen time)
    - Brazil: VISA REQUIRED since April 10, 2025 (reciprocity measure)
    - Canada: eTA required (not visa-free)
    - China: Temporary visa-free until Dec 31, 2026 (90 days since Sept 2025)
    - Indonesia: VoA or eVisa required (not simple visa-free)
    - New Zealand: Trans-Tasman - indefinite residence rights on arrival
    - Thailand: 60 days visa-free (increased from 30 in 2024)
    - Turkey: eVisa required (not visa-free)
    - UK: ETA required from April 2, 2025
    - USA: ESTA required under VWP with E-3 visa benefit
    - Vietnam: eVisa required (not visa-free)

  3. Affected Destinations
    All 42 destinations for Australia passport holders
*/

UPDATE visa_rules SET visa_type = 'visa_free', max_stay_days = 90, stay_window_days = 180, passport_validity_months = 0, return_ticket_required = true, insurance_required = false, sufficient_funds_required = true, notes = 'Visa-free under bilateral agreement for tourism or short business visits. 90 days within any 180-day period. Extendable once for additional 90 days at Migración (DNM). Return ticket may be requested. Proof of sufficient funds may be requested. Yellow fever certificate if arriving from endemic country. Entry smooth at all international airports and land borders.', last_verified = '2026-02-19', updated_at = now() WHERE passport_slug = 'australia' AND destination_slug = 'argentina';

UPDATE visa_rules SET visa_type = 'visa_free', visa_subtype = 'Bilateral agreement', max_stay_days = 90, stay_window_days = null, passport_validity_months = 3, return_ticket_required = true, insurance_required = false, sufficient_funds_required = true, notes = 'Visa-free under bilateral visa waiver agreement with Austria. IMPORTANT: 90 days per entry REGARDLESS of time spent in other Schengen countries — more favorable than standard Schengen 90/180 rule. Passport valid at least 3 months beyond departure and issued within last 10 years. ETIAS expected late 2026 (€20 fee, valid 3 years). Proof of funds and accommodation may be requested. Travel insurance strongly recommended but not mandatory at border.', last_verified = '2026-02-19', updated_at = now() WHERE passport_slug = 'australia' AND destination_slug = 'austria';

UPDATE visa_rules SET visa_type = 'visa_free', max_stay_days = 90, stay_window_days = 180, passport_validity_months = 3, return_ticket_required = true, insurance_required = false, sufficient_funds_required = true, notes = 'Visa-free under Schengen rules. 90 days within any 180-day period across Schengen Area. Passport valid at least 3 months beyond departure and issued within last 10 years. ETIAS expected late 2026 (€20 fee, valid 3 years). Proof of funds and accommodation may be requested at border officers discretion. Travel insurance not a formal mandatory entry requirement at border.', last_verified = '2026-02-19', updated_at = now() WHERE passport_slug = 'australia' AND destination_slug = 'belgium';

UPDATE visa_rules SET visa_type = 'visa_required', visa_subtype = 'Tourist visa (VIVIS)', max_stay_days = 90, stay_window_days = null, passport_validity_months = 6, return_ticket_required = true, insurance_required = false, sufficient_funds_required = true, notes = 'VISA REQUIRED as of April 10, 2025. Brazil reinstated visa requirements for Australian passport holders as reciprocity measure. Tourist visa must be obtained prior to travel via Brazilian government consular system or at Brazilian Embassy in Canberra or Consulate-General in Sydney. No visa on arrival available. Typically 90 days per visit. Passport valid 6 months beyond entry. Return ticket required. Proof of accommodation and funds required. Biometric fingerprinting on arrival. SIGNIFICANT CHANGE from pre-April 2025 visa-free arrangement.', last_verified = '2026-02-19', updated_at = now() WHERE passport_slug = 'australia' AND destination_slug = 'brazil';

UPDATE visa_rules SET visa_type = 'evisa', visa_subtype = 'eTA', max_stay_days = 180, stay_window_days = null, passport_validity_months = 0, return_ticket_required = true, insurance_required = false, sufficient_funds_required = true, notes = 'eTA (Electronic Travel Authorization) MANDATORY before boarding any flight to Canada. Apply at canada.ca/eta. Fee CAD 7. Usually approved within minutes. Valid 5 years or until passport expiry. Multiple entries. Max stay: up to 6 months per visit at border officer discretion. Entry by land or sea does not require eTA. Proof of funds, return ticket, and ties to Australia may be requested. Biometric fingerprinting at border. Working Holiday Visa arrangement for ages 18-35. Australia-Canada consular services sharing agreement.', last_verified = '2026-02-19', updated_at = now() WHERE passport_slug = 'australia' AND destination_slug = 'canada';

UPDATE visa_rules SET visa_type = 'visa_free', max_stay_days = 90, stay_window_days = 180, passport_validity_months = 0, return_ticket_required = true, insurance_required = false, sufficient_funds_required = true, notes = 'Visa-free for tourism or short business stays. 90 days within any 180-day period. Return ticket may be requested. Proof of funds may be requested at land borders. Yellow fever certificate if arriving from endemic country. Working holiday visa available for ages 18-35. Entry seamless at all international airports and land borders.', last_verified = '2026-02-19', updated_at = now() WHERE passport_slug = 'australia' AND destination_slug = 'chile';

UPDATE visa_rules SET visa_type = 'visa_free', visa_subtype = 'Temporary arrangement', max_stay_days = 90, stay_window_days = null, passport_validity_months = 6, return_ticket_required = true, insurance_required = false, sufficient_funds_required = true, notes = 'TEMPORARY bilateral visa-free arrangement valid from July 1, 2024 to December 31, 2026. Up to 90 days per visit (increased from 15 days since September 17, 2025). Outside this window, standard tourist (L) or business (M) visa required. Verify arrangement extension before booking beyond Dec 2026. Passport valid 6 months beyond entry. Return ticket required. Proof of hotel booking or invitation letter required. Biometric fingerprinting on arrival. Australian government advises heightened detention risks under Chinese national security laws.', last_verified = '2026-02-19', updated_at = now() WHERE passport_slug = 'australia' AND destination_slug = 'china';

