UPDATE visa_rules SET visa_type = 'visa_on_arrival', visa_subtype = 'or e-Visa', max_stay_days = 30, stay_window_days = null, passport_validity_months = 6, return_ticket_required = true, insurance_required = false, sufficient_funds_required = true, notes = 'Visa on arrival at major Egyptian international airports. E-Visa also available at visa2egypt.gov.eg, apply at least 7 days before travel. 30 days per entry. Maximum 3 entries and no more than 90 days total per calendar year. Visa fee USD 25 (payable in USD, EUR, or GBP at airport). Return ticket required. Hotel reservation confirmation required. Proof of sufficient funds required. Biometrics may be collected on arrival. E-Visa processed within 5-7 business days.', last_verified = '2026-02-19', updated_at = now() WHERE passport_slug = 'australia' AND destination_slug = 'egypt';

