UPDATE visa_rules SET visa_type = 'evisa', visa_subtype = 'e-Tourist Visa', max_stay_days = 30, stay_window_days = null, passport_validity_months = 6, return_ticket_required = true, insurance_required = false, sufficient_funds_required = true, notes = 'E-Tourist Visa (e-TV) required. Apply at indianvisaonline.gov.in at least 4 days before arrival and no more than 120 days in advance. 30 days per visit. Maximum 2 e-Tourist Visas per calendar year. 1-year or 5-year e-Tourist Visa with longer stays also available at higher fee. Fee USD 25 for 30-day variant. Passport must have at least 2 blank pages. Must arrive via one of 32 designated airports or 5 seaports. Processing 72-96 hours. Return ticket required. Proof of funds and accommodation required.', last_verified = '2026-02-19', updated_at = now() WHERE passport_slug = 'australia' AND destination_slug = 'india';

UPDATE visa_rules SET visa_type = 'visa_on_arrival', visa_subtype = 'or eVisa', max_stay_days = 30, stay_window_days = null, passport_validity_months = 6, return_ticket_required = true, insurance_required = false, sufficient_funds_required = true, notes = 'Visa on Arrival (VoA) or eVisa required — NO blanket visa-free entry for Australians. VoA (IDR 500,000, approx. USD 30) available at designated airports including Bali (Ngurah Rai), Jakarta, Surabaya. eVisa also available via molina.imigrasi.go.id. 30 days per visit. Extendable once for additional 30 days at local immigration office. Passport must have at least one blank page. Return ticket required. Yellow fever certificate if arriving from endemic country. VoA payable in cash (IDR or USD) or card at immigration counter. Biometric fingerprinting on arrival.', last_verified = '2026-02-19', updated_at = now() WHERE passport_slug = 'australia' AND destination_slug = 'indonesia';

UPDATE visa_rules SET visa_type = 'visa_free', visa_subtype = 'Bilateral agreement', max_stay_days = 90, stay_window_days = null, passport_validity_months = 3, return_ticket_required = true, insurance_required = false, sufficient_funds_required = true, notes = 'Visa-free under bilateral visa waiver agreement with Italy. IMPORTANT: 90 days per entry in Italy REGARDLESS of time spent in other Schengen countries — more favorable than standard Schengen 90/180 rule. Passport valid at least 3 months beyond departure and issued within last 10 years. ETIAS expected late 2026 (€20 fee, valid 3 years). Proof of funds, accommodation, and return ticket may be requested. Schengen biometric fingerprinting at external borders. Travel insurance strongly recommended but not mandatory.', last_verified = '2026-02-19', updated_at = now() WHERE passport_slug = 'australia' AND destination_slug = 'italy';

UPDATE visa_rules SET visa_type = 'visa_free', max_stay_days = 90, stay_window_days = null, passport_validity_months = 0, return_ticket_required = true, insurance_required = false, sufficient_funds_required = true, notes = 'Visa-free for tourism or short business visits (granted December 1998 under bilateral agreement). 90 days per visit. Persons previously sentenced to 1+ year imprisonment not eligible and must obtain visa. Return ticket required. Proof of sufficient funds and accommodation required. Biometric fingerprinting and photograph on arrival. Departure tax (JPY 1,000) collected by airline. Working Holiday Visa arrangement for ages 18-30. Japan Visit Web (digital declaration) should be completed before landing. Entry straightforward at all international airports.', last_verified = '2026-02-19', updated_at = now() WHERE passport_slug = 'australia' AND destination_slug = 'japan';

UPDATE visa_rules SET visa_type = 'visa_free', max_stay_days = 90, stay_window_days = null, passport_validity_months = 6, return_ticket_required = true, insurance_required = false, sufficient_funds_required = true, notes = 'Visa-free for tourism or short business stays. 90 days per visit. Passport valid at least 6 months. Return ticket may be requested. Biometric fingerprinting on arrival and departure at all international entry points. Malaysia My Second Home (MM2H) visa available for long-term stays — Australia is designated country for MM2H. Entry efficient at all international airports.', last_verified = '2026-02-19', updated_at = now() WHERE passport_slug = 'australia' AND destination_slug = 'malaysia';

UPDATE visa_rules SET visa_type = 'visa_free', max_stay_days = 180, stay_window_days = null, passport_validity_months = 0, return_ticket_required = false, insurance_required = false, sufficient_funds_required = false, notes = 'Visa-free for tourism, transit, or short business stays. Up to 180 days for tourism. Actual duration at immigration officer discretion written on FMM form. Multiple Immigration Form (FMM) must be completed on arrival or in advance. FMM included in airfare for air travel; fees apply for land entry stays exceeding 7 days. Working Holiday Visa arrangement for ages 18-35. Entry smooth at all international airports and land borders. FMM must be retained and collected on departure.', last_verified = '2026-02-19', updated_at = now() WHERE passport_slug = 'australia' AND destination_slug = 'mexico';

UPDATE visa_rules SET visa_type = 'visa_free', visa_subtype = 'Bilateral agreement', max_stay_days = 90, stay_window_days = null, passport_validity_months = 3, return_ticket_required = true, insurance_required = false, sufficient_funds_required = true, notes = 'Visa-free under bilateral visa waiver agreement with Netherlands. IMPORTANT: 90 days per entry in European Netherlands REGARDLESS of time spent in other Schengen countries — more favorable than standard Schengen 90/180 rule. Passport valid at least 3 months beyond departure and issued within last 10 years. ETIAS expected late 2026 (€20 fee, valid 3 years). Proof of funds and accommodation may be requested. Schengen biometric fingerprinting at external borders.', last_verified = '2026-02-19', updated_at = now() WHERE passport_slug = 'australia' AND destination_slug = 'netherlands';

UPDATE visa_rules SET visa_type = 'visa_free', visa_subtype = 'Trans-Tasman (indefinite)', max_stay_days = null, stay_window_days = null, passport_validity_months = 0, return_ticket_required = false, insurance_required = false, sufficient_funds_required = false, notes = 'UNIQUE PRIVILEGED STATUS under Trans-Tasman Travel Arrangement. Australian citizens granted New Zealand Resident Visa on arrival entitling them to live, work, and study in NZ INDEFINITELY, provided character requirements met. NO NZeTA, NO IVL (NZD 35 levy), NO visitor visa required. Valid Australian passport sufficient. No minimum validity rule. Automated eGates at major NZ airports. Character requirements apply — serious criminal convictions may result in refusal. May apply for NZ citizenship after 5 years residence. Most seamless entry of any international destination for Australians. One of world''s most liberal bilateral immigration frameworks.', last_verified = '2026-02-19', updated_at = now() WHERE passport_slug = 'australia' AND destination_slug = 'new-zealand';

UPDATE visa_rules SET visa_type = 'visa_required', visa_subtype = 'eVisa', max_stay_days = 30, stay_window_days = null, passport_validity_months = 6, return_ticket_required = true, insurance_required = false, sufficient_funds_required = true, notes = 'Visa required prior to travel. Nigeria does not offer visa on arrival for Australians. eVisa most convenient option at portal.immigration.gov.ng or apply at Nigerian High Commission in Canberra. Processing typically 2-3 business days for eVisa. Typically 30 days for tourist visa, extendable at Nigeria Immigration Service. Passport valid at least 6 months with at least 2 blank pages. Return ticket required. Proof of hotel booking or invitation letter required. Yellow fever certificate strongly recommended. Apply at least 2 weeks before travel. Biometrics collected on arrival at Lagos and Abuja airports.', last_verified = '2026-02-19', updated_at = now() WHERE passport_slug = 'australia' AND destination_slug = 'nigeria';

