UPDATE visa_rules SET visa_type = 'visa_free', visa_subtype = 'Bilateral agreement', max_stay_days = 90, stay_window_days = null, passport_validity_months = 3, return_ticket_required = true, insurance_required = false, sufficient_funds_required = true, notes = 'Visa-free under bilateral visa waiver agreement with Portugal. IMPORTANT: 90 days per entry in Portugal REGARDLESS of time spent in other Schengen countries — more favorable than standard Schengen 90/180 rule. Passport valid at least 3 months beyond departure and issued within last 10 years. ETIAS expected late 2026 (€20 fee, valid 3 years). Proof of funds and accommodation may be requested. Portugal D7 Passive Income Visa, Digital Nomad Visa (D8), and Golden Visa popular for Australians. Working Holiday Arrangement for ages 18-35. Schengen biometric fingerprinting at external borders. Travel insurance strongly recommended but not mandatory.', last_verified = '2026-02-19', updated_at = now() WHERE passport_slug = 'australia' AND destination_slug = 'portugal';

UPDATE visa_rules SET visa_type = 'visa_free', max_stay_days = 30, stay_window_days = null, passport_validity_months = 6, return_ticket_required = true, insurance_required = false, sufficient_funds_required = true, notes = 'Visa-free for tourism or short business stays. Free visa on arrival stamp issued at Hamad International Airport. 30 days per visit. Extendable at General Directorate of Passports. Return ticket required. Proof of hotel booking or sufficient funds required. Biometric iris scanning and fingerprinting on arrival. Entry seamless. All visitors subject to customs and security screening.', last_verified = '2026-02-19', updated_at = now() WHERE passport_slug = 'australia' AND destination_slug = 'qatar';

UPDATE visa_rules SET visa_type = 'visa_required', visa_subtype = 'Tourist visa', max_stay_days = 30, stay_window_days = null, passport_validity_months = 0, return_ticket_required = true, insurance_required = false, sufficient_funds_required = false, notes = 'Tourist visa required prior to travel, obtainable from Russian Embassy in Canberra or Consulate-General in Sydney. No visa on arrival. Invitation letter (tourist voucher from registered Russian travel agency) required. 30 days for standard tourist visa. CRITICAL: Australian Government advises DO NOT TRAVEL to Russia due to arbitrary detention risk, ongoing Ukraine conflict, and severely limited consular assistance. Registration with local authorities (hotel or OVIR) within 7 business days mandatory. Direct flights severely limited due to airspace restrictions. Apply well in advance. DFAT warns ability to provide consular assistance is severely limited.', last_verified = '2026-02-19', updated_at = now() WHERE passport_slug = 'australia' AND destination_slug = 'russia';

UPDATE visa_rules SET visa_type = 'visa_on_arrival', visa_subtype = 'or eVisa', max_stay_days = 90, stay_window_days = 365, passport_validity_months = 6, return_ticket_required = true, insurance_required = true, sufficient_funds_required = true, notes = 'Saudi tourist visa on arrival at designated entry points or eVisa at visa.visitsaudi.com. Up to 90 days per year (single or multiple visits). eVisa application can be submitted up to 30 days before travel. Return ticket required. Hotel booking required. Travel insurance required (included in eVisa). Biometric iris scanning and fingerprinting on arrival. Non-Muslim visitors prohibited from entering Mecca. eVisa valid 1 year, multiple entries. Cost approximately USD 80 (includes mandatory health insurance). Approval within minutes to few days. Modest dress standards expected.', last_verified = '2026-02-19', updated_at = now() WHERE passport_slug = 'australia' AND destination_slug = 'saudi-arabia';

UPDATE visa_rules SET visa_type = 'visa_free', max_stay_days = 30, stay_window_days = null, passport_validity_months = 6, return_ticket_required = true, insurance_required = false, sufficient_funds_required = true, notes = 'Visa-free for tourism or short business stays. 30 days per visit. Extendable at Immigration and Checkpoints Authority (ICA) before authorized stay expires. APEC Business Travel Card (ABTC) available for eligible business travelers. Return ticket strongly recommended. Proof of funds and accommodation may be requested. Biometric fingerprinting and photo on arrival and departure. Singapore strictly enforces immigration laws. Automated eGates available at Changi Airport. SG Arrival Card app declaration before landing. Australia-Singapore have strong bilateral ties with numerous corporate immigration pathways.', last_verified = '2026-02-19', updated_at = now() WHERE passport_slug = 'australia' AND destination_slug = 'singapore';

UPDATE visa_rules SET visa_type = 'visa_free', max_stay_days = 30, stay_window_days = null, passport_validity_months = 1, return_ticket_required = true, insurance_required = false, sufficient_funds_required = false, notes = 'Visa-free for tourism, transit, or short business stays. 30 days per visit. Passport valid at least 1 month beyond departure with minimum 2 blank pages for stamps. Yellow fever certificate required if arriving from or transiting through endemic country. Return ticket recommended. Biometric enrollment on arrival. Entry straightforward at OR Tambo International (Johannesburg), Cape Town International, and other major ports. Travel insurance strongly recommended.', last_verified = '2026-02-19', updated_at = now() WHERE passport_slug = 'australia' AND destination_slug = 'south-africa';

UPDATE visa_rules SET visa_type = 'evisa', visa_subtype = 'K-ETA', max_stay_days = 90, stay_window_days = 365, passport_validity_months = 0, return_ticket_required = true, insurance_required = false, sufficient_funds_required = true, notes = 'Visa-free but K-ETA (Korea Electronic Travel Authorization) MANDATORY before travel. Apply at k-eta.go.kr at least 72 hours before departure. Fee KRW 10,000 (approx. USD 7). Valid 3 years for multiple entries. Up to 90 days within any 12-month period. Return ticket required. Proof of funds and accommodation may be requested. Biometric fingerprinting and photo on arrival. Persons with 1+ year imprisonment not eligible. Working Holiday Visa arrangement for ages 18-30. Automated eGates at Incheon, Gimpo, and major airports for enrolled travelers. K-ETA approved within 72 hours.', last_verified = '2026-02-19', updated_at = now() WHERE passport_slug = 'australia' AND destination_slug = 'south-korea';

UPDATE visa_rules SET visa_type = 'visa_free', visa_subtype = 'Bilateral agreement', max_stay_days = 90, stay_window_days = null, passport_validity_months = 3, return_ticket_required = true, insurance_required = false, sufficient_funds_required = true, notes = 'Visa-free under bilateral visa waiver agreement with Spain. IMPORTANT: 90 days per entry in Spain REGARDLESS of time spent in other Schengen countries — more favorable than standard Schengen 90/180 rule. Passport valid at least 3 months beyond departure and issued within last 10 years. ETIAS expected late 2026 (€20 fee, valid 3 years). Proof of funds, accommodation, and return ticket may be requested. Spain Non-Lucrative Visa (NLV) and Digital Nomad Visa popular for Australians. Working Holiday Visa arrangement for ages 18-35. Schengen biometric fingerprinting at external borders. Travel insurance strongly recommended but not mandatory.', last_verified = '2026-02-19', updated_at = now() WHERE passport_slug = 'australia' AND destination_slug = 'spain';

UPDATE visa_rules SET visa_type = 'visa_free', visa_subtype = 'Bilateral agreement', max_stay_days = 90, stay_window_days = null, passport_validity_months = 3, return_ticket_required = true, insurance_required = false, sufficient_funds_required = true, notes = 'Visa-free under bilateral visa waiver agreement with Switzerland. IMPORTANT: 90 days per entry in Switzerland REGARDLESS of time spent in other Schengen countries — more favorable than standard Schengen 90/180 rule. Passport valid at least 3 months beyond departure and issued within last 10 years. ETIAS expected late 2026 will apply to Switzerland as Schengen member (€20 fee, valid 3 years). Proof of funds and accommodation may be requested. Switzerland is non-EU Schengen member but enforces same rules. Schengen biometric fingerprinting at external borders.', last_verified = '2026-02-19', updated_at = now() WHERE passport_slug = 'australia' AND destination_slug = 'switzerland';

UPDATE visa_rules SET visa_type = 'visa_free', max_stay_days = 60, stay_window_days = null, passport_validity_months = 6, return_ticket_required = true, insurance_required = false, sufficient_funds_required = true, notes = 'Visa-free for tourism stays. Entry granted on arrival. 60 days per visit (INCREASED from 30 days in 2024 under Thailand tourism promotion policy). Extendable once for additional 30 days at local immigration office (THB 1,900 fee). Passport valid at least 6 months. Return ticket expected by immigration. Proof of funds (THB 20,000 per person or 40,000 per family) may be requested. Biometric fingerprinting on arrival. Yellow fever certificate if from endemic country. Thailand Digital Arrival Card (TDAC) may be required. Working Holiday Visa arrangement for ages 18-30. Thailand is one of most visited destinations for Australians globally.', last_verified = '2026-02-19', updated_at = now() WHERE passport_slug = 'australia' AND destination_slug = 'thailand';

UPDATE visa_rules SET visa_type = 'evisa', visa_subtype = 'eVisa', max_stay_days = 90, stay_window_days = 180, passport_validity_months = 6, return_ticket_required = true, insurance_required = false, sufficient_funds_required = false, notes = 'eVisa REQUIRED before or upon arrival. eVisa available at evisa.gov.tr. Apply at least 48 hours before travel. Fee USD 60 for Australian citizens. Valid for 180 days from issue, single entry. 90 days within any 180-day period. Visa on arrival available at major airports but eVisa STRONGLY preferred to avoid queues. Passport valid at least 6 months. Return ticket not formally required but may be requested. Proof of accommodation may be requested. Biometric data collected on arrival. eVisa approval usually within minutes to few hours. E-gates available for re-entry at some airports for enrolled travelers.', last_verified = '2026-02-19', updated_at = now() WHERE passport_slug = 'australia' AND destination_slug = 'turkey';

UPDATE visa_rules SET visa_type = 'visa_free', max_stay_days = 30, stay_window_days = null, passport_validity_months = 6, return_ticket_required = true, insurance_required = false, sufficient_funds_required = true, notes = 'Free visa on arrival stamp at any UAE port of entry. 30 days per visit. Extendable for additional 30 days through GDRFA (General Directorate of Residency and Foreigners Affairs). Return ticket required. Proof of sufficient funds and hotel booking required. Biometric iris scanning and fingerprinting on arrival at all UAE ports. Entry seamless at Dubai International, Abu Dhabi International, and all other UAE airports. Australia-UAE maintain strong bilateral business and trade relationship. Visa extension applications online or at GDRFA offices.', last_verified = '2026-02-19', updated_at = now() WHERE passport_slug = 'australia' AND destination_slug = 'united-arab-emirates';

UPDATE visa_rules SET visa_type = 'evisa', visa_subtype = 'UK ETA', max_stay_days = 180, stay_window_days = null, passport_validity_months = 0, return_ticket_required = true, insurance_required = false, sufficient_funds_required = true, notes = 'UK Electronic Travel Authorisation (ETA) MANDATORY from April 2, 2025. Apply via UK ETA app or online at gov.uk. Fee GBP 16 (approx. USD 20). Valid 2 years or until passport expiry. Multiple entries. Up to 6 months per visit. Return ticket may be requested. Proof of funds and purpose of visit may be verified. Biometric checks at UK border. eGates at Heathrow, Gatwick, and major airports for Australian passport holders. Youth Mobility Scheme (Working Holiday Visa) for ages 18-35, extended to allow stays up to 3 years. ETA approved within hours (up to 3 business days). Australia-UK have very close bilateral ties with high traveler volumes.', last_verified = '2026-02-19', updated_at = now() WHERE passport_slug = 'australia' AND destination_slug = 'united-kingdom';

UPDATE visa_rules SET visa_type = 'evisa', visa_subtype = 'ESTA', max_stay_days = 90, stay_window_days = null, passport_validity_months = 0, return_ticket_required = true, insurance_required = false, sufficient_funds_required = true, notes = 'ESTA (Electronic System for Travel Authorization) MANDATORY under Visa Waiver Program (VWP). Apply at esta.cbp.dhs.gov at least 72 hours before departure. Fee USD 21. Valid 2 years or until passport expiry. Up to 90 days per visit. Cannot be extended under VWP. Passport must be e-passport (biometric chip). Return ticket required. Biometric fingerprinting and photo on arrival. CBP conducts thorough entry interviews. CRITICAL: Overstaying even 1 day permanently forfeits ESTA eligibility. Persons who traveled to Iran, Iraq, Libya, North Korea, Somalia, Sudan, Syria, or Yemen since March 1, 2011 ineligible for ESTA. MAJOR BENEFIT: E-3 visa exclusively for Australian nationals — much faster processing and lower demand than H-1B, highly attractive for skilled professionals. E-3 visa is significant bilateral benefit for Australians.', last_verified = '2026-02-19', updated_at = now() WHERE passport_slug = 'australia' AND destination_slug = 'united-states';

UPDATE visa_rules SET visa_type = 'evisa', visa_subtype = 'eVisa', max_stay_days = 90, stay_window_days = null, passport_validity_months = 6, return_ticket_required = true, insurance_required = false, sufficient_funds_required = true, notes = 'eVisa REQUIRED before travel. Apply at evisa.xuatnhapcanh.gov.vn. Fee USD 25. Valid 90 days, multiple entries. Apply at least 3 business days before travel (allow more during peak periods). Visa on arrival technically available but requires pre-approval letter and generally only suitable for air travel — eVisa STRONGLY recommended. Passport valid at least 6 months. Return ticket may be requested. Proof of accommodation and funds may be requested. eVisa straightforward online application, approved within 3 business days. Arrival smooth at Noi Bai (Hanoi), Tan Son Nhat (HCMC), Da Nang, and all major ports.', last_verified = '2026-02-19', updated_at = now() WHERE passport_slug = 'australia' AND destination_slug = 'vietnam';
